solution:
function getExactMiddle(arr) {
  const len = arr.length;
  if (len === 0) return [];
  const mid = Math.floor(len / 2);
  if (len % 2 === 0) {
    return arr.slice(mid - 1, mid + 1);
  } else {
    return arr.slice(mid, mid + 1);
  }
}

